#include<bits/stdc++.h>using namespace std;int ans[1000000],vis[1000000];int n,cnt=0;void dfs(int cur){        if(cnt==n)return;    if(cur==n+1)    {        for(int i = 1; i <= n ; i++)cout<<ans[i]<<" ";        cout<<'\n';        cnt++;        return;    }    for(int i = 1; i <= n; i++)    {        if(!vis[i])        {            if(cur>=3)            {                if(ans[cur-1]+ans[cur-2]==i)continue;;            }            vis[i]=1;            ans[cur]=i;            dfs(cur+1);            vis[i]=0;        }       }}int main(){    int t;    cin>>t;    while(t--)    {        cin>>n;        cnt=0;        dfs(1);    }    return 0;}